  ('locality-7fec267e-moex-00180', 'locality-7fec267e', 'locality-7fec267e-moex-112-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '下列何者得以法規命令規範之？', '["對於因全民健康保險所生之權利義務", "課予納稅之義務", "時效制度", "特別公課徵收之要件及程序"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "301", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00181', 'locality-7fec267e', 'locality-7fec267e-moex-112-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '人民甲欲申請建築許可，經乙機關審查通過並發給執照。在該建築許可的法定救濟期間經過後， 乙機關才發現該建築許可之作成具有瑕疵，欲加以撤銷。下列敘述何者正確？', '["基於依法行政原則，該違法之建築許可不得作為甲的信賴基礎", "即使當初是因為甲提供錯誤之資料，致使乙作成該建築許可時，甲仍然可主張信賴保護", "縱使甲之信賴值得保護，但經權衡信賴利益與公益之後，乙仍然可以撤銷該建築許可，只是應 給予補償", "若該建築許可經乙撤銷後，原則上自撤銷之日起失其效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "301", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00182', 'locality-7fec267e', 'locality-7fec267e-moex-112-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '下列何者非屬行政處分？', '["經濟部標準檢驗局於申請後，認定受檢驗商品為合格", "人民未經申請集會而集會，警察舉牌命令立即解散集會遊行", "衛生主管機關在官方網站上公告傳染病大流行，促請民眾於公眾聚集場所配戴口罩", "主管機關對於未履行拆除義務之違建行為人發出通知，告戒7日後將逕行拆除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "301", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00183', 'locality-7fec267e', 'locality-7fec267e-moex-112-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '甲因欠稅超過新臺幣1,000萬元，財政部因而依稅捐稽徵法第24條第3項規定函請內政部移民署 限制甲出境，嗣經該署向甲核發限制出境之處分。下列敘述何者正確？', '["該限制出境處分係屬根據機關間權限委託所作成之行政處分", "該限制出境處分係屬多階段之行政處分", "該限制出境處分係屬根據機關間權限委任所作成之行政處分", "該限制出境處分係屬對人之一般處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "301", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00184', 'locality-7fec267e', 'locality-7fec267e-moex-112-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '依行政程序法規定，關於雙務契約之締結，下列敘述何者錯誤？', '["行政機關與人民得締結雙務契約，互負給付義務", "雙務契約之締結，以行政機關有裁量權為限", "契約應載明人民給付之特定用途", "人民與機關之給付義務應相當，且有正當合理之關聯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "301", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00185', 'locality-7fec267e', 'locality-7fec267e-moex-112-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '依行政程序法規定，行政機關擬訂法規命令時，應於政府公報或新聞紙公告。該公告之法律性質 為何？', '["行政處分", "行政契約", "行政事實行為", "行政命令"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "301", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00186', 'locality-7fec267e', 'locality-7fec267e-moex-112-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '下列何者屬裁罰性之不利處分？', '["證券商自受領證券業務特許證照，逾3個月未開始營業，遭主管機關撤銷其特許", "外國船舶因違反海洋污染防治法所生之損害賠償責任，在未履行前，遭港口管理機關限制船舶 及相關船員離境", "全民健康保險醫事服務機構因違反相關法令，遭衛生福利部中央健康保險署停止特約", "招標機關將廠商借用他人名義或證件之行為刊登於政府採購公報 31230"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "301", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00187', 'locality-7fec267e', 'locality-7fec267e-moex-112-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '關於即時強制之損失補償，下列敘述何者正確？', '["損失補償，應以回復原狀為原則，例外以金錢為之", "損失補償不以補償實際所受之特別損失為限", "因可歸責於該人民之事由，執行機關依法實施即時強制，致其生命、身體或財產遭受特別損失 時，得請求補償", "損失補償，應於知有損失後，2年內向執行機關請求之。但自損失發生後，經過5年者，不得為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "301", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00188', 'locality-7fec267e', 'locality-7fec267e-moex-112-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '關於行政程序法聽證，下列敘述何者正確？', '["須有法律規定作為舉行聽證之依據", "得為預備聽證，必要時亦得再為聽證", "經聽證程序作成之行政處分，無後續救濟管道", "聽證以不公開為原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "301", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00189', 'locality-7fec267e', 'locality-7fec267e-moex-112-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '依實務見解，人民甲依訴願法第2條規定提起訴願，受理訴願機關尚未作成決定前，應作為之乙 機關已作成行政處分，而甲仍對於乙機關所作成之處分向訴願機關表示不服，此時受理訴願機關 應如何處理？', '["訴願機關應續行訴願程序，對嗣後所為之行政處分進行審查", "不論該處分有利或不利於訴願人，皆應依訴願法第82條第2項規定駁回訴願", "因乙機關已作成行政處分，甲之訴願無理由，應駁回其訴願", "因乙機關已作成行政處分，甲已無權利保護必要，應駁回其訴願"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "301", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL)
